class WebViewScreen extends StatefulWidget {
  @override
  _WebViewScreenState createState() => _WebViewScreenState();
}

class _WebViewScreenState extends State<WebViewScreen> {
  late WebViewController _controller;
  final ImagePicker _imagePicker = ImagePicker();
  FirebaseMessaging? _firebaseMessaging;
  bool _isLoading = true;

  @override
  void initState() {
    super.initState();
    _initializePushNotifications();
  }

  void _initializePushNotifications() async {
    try {
      _firebaseMessaging = FirebaseMessaging.instance;
      
      NotificationSettings settings = await _firebaseMessaging!.requestPermission(
        alert: true,
        badge: true,
        sound: true,
      );

      if (settings.authorizationStatus == AuthorizationStatus.authorized) {
        String? token = await _firebaseMessaging!.getToken();
        print('FCM Token: $token');
        
        FirebaseMessaging.onMessage.listen((RemoteMessage message) {
          _handlePushNotification(message);
        });

        FirebaseMessaging.onMessageOpenedApp.listen((RemoteMessage message) {
          _handlePushNotification(message);
        });
      }
    } catch (e) {
      print('Error initializing push notifications: $e');
    }
  }

  void _handlePushNotification(RemoteMessage message) {
    final data = jsonEncode({
      'title': message.notification?.title ?? '',
      'body': message.notification?.body ?? '',
      'data': message.data,
    });
    
    _controller.runJavaScript(
      "if(window.onPushNotification) { window.onPushNotification($data); }"
    );
  }

  Future<void> _openCamera() async {
    try {
      final XFile? photo = await _imagePicker.pickImage(
        source: ImageSource.camera,
        maxWidth: 1920,
        maxHeight: 1080,
        imageQuality: 85,
      );
      
      if (photo != null) {
        final bytes = await photo.readAsBytes();
        final base64Image = base64Encode(bytes);
        
        _controller.runJavaScript(
          "if(window.onCameraResult) { window.onCameraResult('data:image/jpeg;base64,$base64Image'); }"
        );
      } else {
        _controller.runJavaScript(
          "if(window.onCameraResult) { window.onCameraResult(null); }"
        );
      }
    } catch (e) {
      print('Error opening camera: $e');
      _controller.runJavaScript(
        "if(window.onCameraError) { window.onCameraError('${e.toString()}'); }"
      );
    }
  }

  Future<void> _pickImageFromGallery() async {
    try {
      final XFile? image = await _imagePicker.pickImage(
        source: ImageSource.gallery,
        maxWidth: 1920,
        maxHeight: 1080,
        imageQuality: 85,
      );
      
      if (image != null) {
        final bytes = await image.readAsBytes();
        final base64Image = base64Encode(bytes);
        
        _controller.runJavaScript(
          "if(window.onGalleryResult) { window.onGalleryResult('data:image/jpeg;base64,$base64Image'); }"
        );
      } else {
        _controller.runJavaScript(
          "if(window.onGalleryResult) { window.onGalleryResult(null); }"
        );
      }
    } catch (e) {
      print('Error picking image: $e');
      _controller.runJavaScript(
        "if(window.onGalleryError) { window.onGalleryError('${e.toString()}'); }"
      );
    }
  }

  Future<String?> _getPushToken() async {
    try {
      if (_firebaseMessaging != null) {
        return await _firebaseMessaging!.getToken();
      }
      return null;
    } catch (e) {
      print('Error getting push token: $e');
      return null;
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Hybrid WebView'),
        actions: [
          IconButton(
            icon: Icon(Icons.refresh),
            onPressed: () {
              _controller.reload();
            },
          ),
        ],
      ),
      body: Stack(
        children: [
          WebView(
            initialUrl: 'https://your-mobile-website.com',
            javascriptMode: JavascriptMode.unrestricted,
            onWebViewCreated: (WebViewController controller) {
              _controller = controller;
            },
            onPageStarted: (String url) {
              setState(() {
                _isLoading = true;
              });
            },
            onPageFinished: (String url) {
              setState(() {
                _isLoading = false;
              });
              
              _controller.runJavaScript('''
                console.log('Flutter WebView Bridge initialized');
              ''');
            },
            javascriptChannels: <JavascriptChannel>{
              JavascriptChannel(
                name: 'FlutterBridge',
                onMessageReceived: (JavascriptMessage message) async {
                  try {
                    final data = jsonDecode(message.message);
                    final action = data['action'];
                    
                    switch (action) {
                      case 'openCamera':
                        await _openCamera();
                        break;
                      case 'openGallery':
                        await _pickImageFromGallery();
                        break;
                      case 'getPushToken':
                        final token = await _getPushToken();
                        _controller.runJavaScript(
                          "if(window.onPushToken) { window.onPushToken('$token'); }"
                        );
                        break;
                      case 'showToast':
                        final text = data['text'] ?? 'Message';
                        ScaffoldMessenger.of(context).showSnackBar(
                          SnackBar(content: Text(text)),
                        );
                        break;
                      case 'vibrate':
                        print('Vibrate requested');
                        break;
                      case 'shareContent':
                        final shareData = data['data'];
                        print('Share requested: $shareData');
                        break;
                      default:
                        print('Unknown action: $action');
                    }
                  } catch (e) {
                    print('Error handling message: $e');
                  }
                },
              ),
            },
            gestureNavigationEnabled: true,
            allowsInlineMediaPlayback: true,
          ),
          if (_isLoading)
            Center(
              child: CircularProgressIndicator(),
            ),
        ],
      ),
    );
  }
}